// 三载体一致：按裁剪几何调用原生 slide API，只产 Blob
import PptxGenJS from 'https://cdn.jsdelivr.net/npm/pptxgenjs@4/+esm';
const p=data.presentation, pptx=new PptxGenJS(); pptx.layout=p.layout??'LAYOUT_WIDE';
for (const k of ['author','company','subject','title']) if (p[k] != null) pptx[k]=p[k];
for (const s of p.slides) { const slide=pptx.addSlide(); if(s.background) slide.background=s.background; for(const e of s.elements) { if(e.kind==='text') slide.addText(e.text,e.options); else if(e.kind==='shape') slide.addShape(pptx.ShapeType[e.shape],e.options); else if(e.kind==='image') slide.addImage({...e.source,...e.options}); } }
const blob = await pptx.write({outputType:'blob'});
